"use client";
import React, { Suspense, useRef } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import { Preload } from "@react-three/drei";
import * as THREE from "three";
import WindowModel from "../models/WindowModel";
import CloudContainer from "../models/Cloud";

const PortalContent = () => {
  const groupRef = useRef<THREE.Group>(null);

  useFrame((state, delta) => {
    // Localized cursor panning inside this portal bounds
    const targetX = state.pointer.x * 1.5;
    const targetY = state.pointer.y * 1.0;
    if (groupRef.current) {
      groupRef.current.rotation.y = THREE.MathUtils.damp(groupRef.current.rotation.y, targetX, 2.5, delta);
      groupRef.current.rotation.x = THREE.MathUtils.damp(groupRef.current.rotation.x, -targetY * 0.5, 2.5, delta);
      
      // Floating motion
      const elapsed = state.clock.getElapsedTime();
      groupRef.current.position.y = Math.sin(elapsed * 0.5) * 0.1;
    }
  });

  return (
    <group ref={groupRef}>
      <ambientLight intensity={0.6} />
      <pointLight position={[5, 5, 5]} intensity={1.5} />
      <directionalLight position={[-3, 5, -3]} intensity={1.0} />
      
      {/* Local clouds */}
      <CloudContainer />

      {/* 3D Jendela (Window) Model scaled to fit inside the portal frame */}
      <group position={[0, -0.6, 0.5]} scale={0.4}>
        <WindowModel />
      </group>
    </group>
  );
};

const Hero3DPortal = React.memo(() => {
  return (
    <div className="hero-3d-portal-wrapper">
      <div className="hero-3d-portal-card">
        {/* Holographic glowing lines around card */}
        <div className="portal-border-glow"></div>
        <div className="portal-terminal-tag">[ SYS.PORTAL_01 • WINDOW_SCENE ]</div>
        
        <Canvas
          camera={{ position: [0, 0, 3.2], fov: 50 }}
          gl={{ antialias: true, alpha: true }}
          dpr={[1, 1.5]}
          style={{ width: "100%", height: "100%" }}
        >
          <Suspense fallback={null}>
            <PortalContent />
            <Preload all />
          </Suspense>
        </Canvas>
      </div>

      <style dangerouslySetInnerHTML={{ __html: `
        .hero-3d-portal-wrapper {
          position: relative;
          perspective: 1000px;
          margin-top: 15px;
          display: flex;
          justify-content: center;
        }
        .hero-3d-portal-card {
          position: relative;
          width: 320px;
          height: 220px;
          border-radius: 16px;
          background: rgba(10, 10, 10, 0.45);
          backdrop-filter: blur(12px);
          -webkit-backdrop-filter: blur(12px);
          border: 1px solid var(--glass-border);
          overflow: hidden;
          box-shadow: 0 8px 32px rgba(0, 243, 255, 0.08);
          transition: all 0.5s ease;
        }
        .hero-3d-portal-card:hover {
          border-color: var(--accent-cyan);
          box-shadow: 0 12px 40px rgba(0, 243, 255, 0.2);
          transform: translateY(-5px);
        }
        .portal-border-glow {
          position: absolute;
          top: 0;
          left: 0;
          width: 100%;
          height: 100%;
          border-radius: 16px;
          background: linear-gradient(135deg, rgba(0, 243, 255, 0.2) 0%, transparent 100%);
          pointer-events: none;
          z-index: 1;
        }
        .portal-terminal-tag {
          position: absolute;
          top: 10px;
          left: 12px;
          font-family: 'Rajdhani', sans-serif;
          font-weight: 700;
          font-size: 0.65rem;
          color: var(--accent-cyan);
          letter-spacing: 0.1em;
          z-index: 2;
          pointer-events: none;
          opacity: 0.8;
        }
      `}} />
    </div>
  );
});

Hero3DPortal.displayName = "Hero3DPortal";
export default Hero3DPortal;
